+pub fn write_ts_resolution_index_artifacts(
+    output_dir: &Path,
+    scenario_id: &str,
+    commands: &[String],
+    traces: &[TsResolutionTraceEvent],
+    bundle: &TsModuleResolutionIndexBundle,
+    validation: &TsResolutionIndexValidationReport,
+    step_logs: &[TsResolutionIndexStepLog],
